  "type": "LEARNING_CARD",
  "title": "Causes of Cold Sensations",
  "lessonText": "Understanding the causes of cold sensations can aid in effective fever management.",
  "data": {
    "learningCards": [
      {
        "title": "Environmental Factors",
        "content": "Exposure to cold weather can lead to cold sensations.\n\n- Wind chill can exacerbate the feeling.\n- Wet clothing increases heat loss."
      },
      {
        "title": "Physiological Responses",
        "content": "The body may react to illness with cold sensations.\n\n- Fever can cause chills.\n- Infections may trigger vasoconstriction."
      },
      {
        "title": "Circulatory Issues",
        "content": "Poor circulation can result in cold extremities.\n\n- Conditions like Raynaud's disease can worsen symptoms.\n- Blood flow reduction leads to cold sensations."
      },
      {
        "title": "Metabolic Factors",
        "content": "Metabolic rate influences body temperature perception.\n\n- Hypothyroidism can cause cold intolerance.\n- Low energy availability affects heat production."
      }
    ]
  }
}
